package gizclaw

//go:generate sh -c "set -eu; root=$DOLLAR(cd ../../.. && pwd); venv=\"$DOLLAR{root}/.tmp/nanopb-venv\"; stamp=\"$DOLLAR{venv}/.gizclaw-nanopb-0.4.9.1\"; protoc=$DOLLAR(command -v protoc); if [ ! -x \"$DOLLAR{venv}/bin/python\" ] || [ ! -f \"$DOLLAR{stamp}\" ]; then rm -rf \"$DOLLAR{venv}\"; python3 -m venv \"$DOLLAR{venv}\"; \"$DOLLAR{venv}/bin/python\" -m pip install --disable-pip-version-check --quiet 'protobuf>=3.20,<7' 'grpcio-tools>=1.0'; fi; payload_files=$DOLLAR(find \"$DOLLAR{root}/api/proto/rpc/payload\" -name '*.proto' | sort); PATH=\"$DOLLAR{venv}/bin:$DOLLAR{PATH}\" PROTOCOL_BUFFERS_PYTHON_IMPLEMENTATION=python \"$DOLLAR{protoc}\" -I \"$DOLLAR{root}/api/proto/rpc\" --plugin=protoc-gen-nanopb=\"$DOLLAR{root}/third_party/nanopb/upstream/generator/protoc-gen-nanopb\" --nanopb_out=\"$DOLLAR{root}/sdk/c/gizclaw/generated\" --nanopb_opt=-I\"$DOLLAR{root}/api/proto/rpc\" --nanopb_opt=-f\"$DOLLAR{root}/api/proto/rpc/nanopb.options\" --nanopb_opt=-q google/protobuf/struct.proto \"$DOLLAR{root}/api/proto/rpc/rpc.proto\" $DOLLAR{payload_files}; : > \"$DOLLAR{stamp}\""
